    }

    const totalSum = aList.reduce((sum, val) => (sum + val) % MOD, 0);
    const sumSquares = aList.reduce((sum, val) => (sum + val * val) % MOD, 0);

    const numerator = (totalSum * totalSum - sumSquares + MOD) % MOD;
    const ans = (numerator * inv2) % MOD;

    return ans;
}
